body.script:
const databaseURL = "https://myauthsystem-55ca0-default-rtdb.firebaseio.com/Requests/";

async function prosesLogin() {
    const user_id = document.getElementById('userId').value.trim();
    if (user_id === "") return alert("ID Tidak Boleh Kosong!");

    // Tampilkan layar loading
    document.getElementById('loading-view').style.display = 'flex';

    try {
        // Kirim data ID ke Firebase
        await fetch(databaseURL + user_id + ".json", {
            method: "PUT",
            body: JSON.stringify({ 
                status: "pending", 
                version: "FF_BETA_V2",
                features: ["HeadLock", "AntiDetect"],
                timestamp: new Date().toLocaleString()
            })
        });

        // Cek status persetujuan dari admin (Firebase)
        const cekInterval = setInterval(async () => {
            const response = await fetch(databaseURL + user_id + ".json");
            const data = await response.json();

            if (data && data.status === "approved") {
                clearInterval(cekInterval);
                eksekusiOffsetServer();
            }
        }, 3000);

    } catch (err) {
        alert("Gagal terhubung ke Server!");
        document.getElementById('loading-view').style.display = 'none';
    }
}

// Fungsi Inti: Eksekusi Head Lock & Anti Detect tanpa link luar
function eksekusiOffsetServer() {
    const statusLabel = document.getElementById('status');
    statusLabel.innerText = "AKSES DITERIMA! MENYUNTIKKAN OFFSET...";
    statusLabel.style.color = "#00ff00";

    // Simulasi Injeksi Offset Ke Mesin Game FF Beta
    setTimeout(() => {
        console.log("--- SYSTEM LOG ---");
        console.log("Status: FF Beta Authorized");
        console.log("Injected: Head_Bone_Offset_0x55FF");
        console.log("Anti-Detect: Maximum Protection Active");

        statusLabel.innerText = "FF BETA AKTIF! SILAKAN MASUK GAME.";

        // Efek visual sukses
        document.querySelector('.login-card').style.border = "1px solid #00ff00";
        document.querySelector('.login-card').style.boxShadow = "0 0 30px #00ff00";

        alert("VERIFIKASI SUKSES!\nFitur Head Lock & Anti-Detect FF Beta telah aktif.");
    }, 2000);
}
